export type Cell = readonly [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

function neighborsOf([x, y]: Cell): Cell[] {
  const neighbors: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx !== 0 || dy !== 0) neighbors.push([x + dx, y + dy]);
    }
  }
  return neighbors;
}

function countLiveNeighbors(cell: Cell, liveSet: ReadonlySet<string>): number {
  return neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
}

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));

  const survivors = liveCells.filter((cell) => {
    const count = countLiveNeighbors(cell, liveSet);
    return count === 2 || count === 3;
  });

  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      if (!liveSet.has(cellKey(neighbor))) candidates.set(cellKey(neighbor), neighbor);
    }
  }

  const births = [...candidates.values()].filter(
    (cell) => countLiveNeighbors(cell, liveSet) === 3,
  );

  return [...survivors, ...births];
}

